const esc = (v) => v ? String(v).replace(/'/g, "''") : null;

const items = [];
for (const item of $input.all()) {
  const d = item.json;
  items.push({
    json: {
      numero_documento: esc(d.NUMERODOCUMENTO),
      especie_documento: esc(d.ESPECIEDOCUMENTO),
      numero_faturamento: esc(d.NUMEROFATURAMENTO),
      especie_faturamento: esc(d.ESPECIEFATURAMENTO),
      data_faturamento: d.DATAFATURAMENTO || null,
      codigo_empresa: d.CODIGOEMPRESA || null,
      codigo_vendedor: esc(d.CODIGOVENDEDOR),
      nome_operador: esc(d.NOMEOPERADOR),
      codigo_cliente: esc(d.CODIGOCLIENTE),
      nome_cliente: esc(d.NOMECLIENTE),
      valor_contabil: parseFloat(d.VALORCONTABIL) || 0,
      valor_frete: parseFloat(d.VALORFRETE) || 0,
      itens: esc(d.ITENS),
      tipo_operacao: esc(d.TIPOOPERACAO),
      cfop: esc(d.CFOP),
      chave_acesso: esc(d.CHAVEACESSO),
      nf_original_numero: esc(d.NFORIGINALNUMERO),
      nf_original_chave: esc(d.NFORIGINALCHAVE),
      motivo_cancelamento: esc(d.MOTIVOCANCELAMENTO),
      situacao_nf: esc(d.SITUACAONF),
      cliente: 'Marcel'
    }
  });
}

return items;

